svg.script:
// تخزين النصوص المطلوبة
const textData = {
  arabTitle: "مساحة إعلانية متاحة",
  arabDesc: 'تواصل مع إدارة "صوان" لحجز هذه المساحة',
  engTitle: "Advertising space available",
  engDesc: "Contact Siwane management to reserve this space"
};

const typeSpeed = 50; // سرعة كتابة الحرف بالملي ثانية
const displayTime = 8000; // وقت بقاء النص على الشاشة (8 ثواني)

// دالة لمسح كل الشاشة
function clearScreen() {
  document.getElementById("line1").textContent = "";
  document.getElementById("line2").textContent = "";
  document.getElementById("line3").textContent = "";
  document.getElementById("line4").textContent = "";
}

// دالة لكتابة النص حرفاً بحرف
function typeWriter(elementId, text) {
  return new Promise(resolve => {
    const el = document.getElementById(elementId);
    let i = 0;
    function type() {
      if (i < text.length) {
        el.textContent += text.charAt(i);
        i++;
        setTimeout(type, typeSpeed);
      } else {
        resolve(); // انتهت الكتابة
      }
    }
    type();
  });
}

// دالة للانتظار (8 ثواني)
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// الدورة الرئيسية التي لا تنتهي
async function startAnimation() {
  // إخفاء كل شيء في البداية
  clearScreen();

  while (true) {
    // ===== المرحلة الأولى: النص العربي =====
    await typeWriter("line1", textData.arabTitle); // يكتب العنوان العربي
    await sleep(300); // استراحة قصيرة جداً للعين
    await typeWriter("line3", textData.arabDesc); // يكتب الوصف العربي

    await sleep(displayTime); // ينتظر 8 ثواني
    clearScreen(); // يمسح الشاشة

    // ===== المرحلة الثانية: النص الإنجليزي =====
    await typeWriter("line2", textData.engTitle); // يكتب العنوان الإنجليزي
    await sleep(300); 
    await typeWriter("line4", textData.engDesc); // يكتب الوصف الإنجليزي

    await sleep(displayTime); // ينتظر 8 ثواني
    clearScreen(); // يمسح الشاشة لتبدأ الدورة من جديد
  }
}

// تشغيل الدورة بمجرد تحميل الصورة
window.addEventListener("load", startAnimation);
